<span class="line">console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>instance2<span class="token punctuation">.</span>colors<span class="token punctuation">)</span><span class="token punctuation">;</span> 			<span class="token comment">// [ &#39;red&#39;, &#39;blue&#39;, &#39;green&#39; ]</span></span>
